package shell.org.apache.accumulo.shell.commands;

public class DeleteManyCommand extends ScanCommand { private Option forceOpt ; @ Override public int execute ( final String fullCommand , final CommandLine cl , final Shell shellState ) throws Exception { final String tableName = OptUtil . getTableOpt ( cl , shellState ) ; final ScanInterpreter interpeter = getInterpreter ( cl , tableName , shellState ) ; final Authorizations auths = getAuths ( cl , shellState ) ; final Scanner scanner = shellState . getConnector ( ) . createScanner ( tableName , auths ) ; scanner . addScanIterator ( new IteratorSetting ( Integer . MAX_VALUE , "NOVALUE" , SortedKeyIterator . class ) ) ; addScanIterators ( shellState , cl , scanner , tableName ) ; scanner . setRange ( getRange ( cl , interpeter ) ) ; scanner . setTimeout ( getTimeout ( cl ) , TimeUnit . MILLISECONDS ) ; fetchColumns ( cl , scanner , interpeter ) ; final BatchWriter writer = shellState . getConnector ( ) . createBatchWriter ( tableName , new BatchWriterConfig ( ) . setTimeout ( getTimeout ( cl ) , TimeUnit . MILLISECONDS ) ) ; shellState . printLines ( new DeleterFormatter ( writer , scanner , cl . hasOption ( timestampOpt . getOpt ( ) ) , shellState , cl . hasOption ( forceOpt . getOpt ( ) ) ) , false ) ; return 0 ; } @ Override public String description ( ) { return "scans a table and deletes the resulting records" ; } @ Override public Options getOptions ( ) { forceOpt = new Option ( "f" , "force" , false , "force deletion without prompting" ) ; final Options opts = super . getOptions ( ) ; opts . addOption ( forceOpt ) ; opts . addOption ( OptUtil . tableOpt ( "table to delete entries from" ) ) ; return opts ; } }